mapper.select:
SELECT USER_ID AS userId, NAME AS userName, PHONE AS userPhone, ROLE AS role, LAWYER_STATUS AS lawyerStatus, LICENSE_FILE AS licenseFile, JOIN_DATE AS requestDate FROM PRJ01.USERS WHERE 1=1
AND LAWYER_STATUS IS NOT NULL
AND ROLE = #{role}
AND LAWYER_STATUS = #{status}
ORDER BY CASE WHEN LAWYER_STATUS = 'PENDING' THEN 1 ELSE 2 END, JOIN_DATE DESC

mapper.update:
UPDATE PRJ01.USERS SET LAWYER_STATUS = #{status},
ROLE = 'ROLE_LAWYER', STATUS = '정상', REJECT_REASON = NULL
ROLE = 'ROLE_USER', STATUS = '정상', REJECT_REASON = #{rejectReason}
WHERE USER_ID = #{lawyerId}
